// Calculate days until due and assign threshold bucket for each obligation
const today = new Date();
today.setHours(0, 0, 0, 0);

const items = $input.all();
const results = [];

for (const item of items) {
  const ob = item.json;
  const dueDate = new Date(ob.due_date);
  dueDate.setHours(0, 0, 0, 0);
  const daysUntilDue = Math.floor((dueDate - today) / (1000 * 60 * 60 * 24));

  let threshold = 'no_action';
  if (ob.status === 'overdue' || daysUntilDue < 0) threshold = 'overdue';
  else if (daysUntilDue === 0) threshold = 'due_today';
  else if (daysUntilDue <= 14) threshold = '14_day';
  else if (daysUntilDue <= 30) threshold = '30_day';

  // Calculate current quarter for logging
  const month = today.getMonth();
  const quarter = 'Q' + (Math.floor(month / 3) + 1);

  // Build email HTML based on threshold
  const urgencyMap = {
    '30_day': { color: '#3b82f6', label: 'Informational', prefix: 'Upcoming' },
    '14_day': { color: '#f59e0b', label: 'ESCALATION', prefix: 'Action Needed Soon' },
    'due_today': { color: '#ef4444', label: 'ACTION REQUIRED', prefix: 'Due Today' },
    'overdue': { color: '#dc2626', label: 'OVERDUE', prefix: 'Past Due' }
  };

  let email_html = '';
  let email_subject = '';
  const style = urgencyMap[threshold];
  if (style) {
    email_subject = `Compliance ${style.label}: ${ob.obligation_name} due ${ob.due_date}`;
    email_html = `<!DOCTYPE html><html><body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;"><div style="border-left: 4px solid ${style.color}; padding: 16px; margin: 16px 0;"><h2 style="color: ${style.color}; margin: 0 0 8px;">${style.prefix}: ${ob.obligation_name}</h2><p><strong>Status:</strong> ${style.label}</p><p><strong>Due Date:</strong> ${ob.due_date}</p><p><strong>Days Until Due:</strong> ${daysUntilDue}</p><p><strong>Description:</strong> ${ob.description || 'N/A'}</p><p><strong>Owner:</strong> ${ob.owner || 'N/A'}</p><p><strong>Category:</strong> ${ob.category || 'N/A'}</p>${ob.notes ? '<p><strong>Notes:</strong> ' + ob.notes + '</p>' : ''}</div><p style="color: #666; font-size: 12px;">Compliance Sentinel | Faith & Harmony LLC | Automated Governance System</p></body></html>`;
  }

  results.push({
    json: {
      ...ob,
      days_until_due: daysUntilDue,
      threshold,
      needs_sms: threshold === '14_day' || threshold === 'overdue',
      needs_email: threshold !== 'no_action',
      email_html,
      email_subject,
      current_quarter: quarter,
      fiscal_year: today.getFullYear(),
      sms_message: (threshold === '14_day' || threshold === 'overdue')
        ? `COMPLIANCE ${style ? style.label : 'ALERT'}: ${ob.obligation_name} due in ${daysUntilDue} days. Action needed. Check email for details.`
        : ''
    }
  });
}

return results;

// Filter for 14-day and overdue obligations only (daily path)
const today = new Date();
today.setHours(0, 0, 0, 0);

const items = $input.all();
const results = [];

for (const item of items) {
  const ob = item.json;
  const dueDate = new Date(ob.due_date);
  dueDate.setHours(0, 0, 0, 0);
  const daysUntilDue = Math.floor((dueDate - today) / (1000 * 60 * 60 * 24));

  let threshold = 'no_action';
  if (ob.status === 'overdue' || daysUntilDue < 0) threshold = 'overdue';
  else if (daysUntilDue === 0) threshold = 'due_today';
  else if (daysUntilDue <= 14) threshold = '14_day';

  // Only pass through obligations due within 14 days or overdue
  if (threshold === 'no_action') continue;

  const month = today.getMonth();
  const quarter = 'Q' + (Math.floor(month / 3) + 1);

  const urgencyMap = {
    '14_day': { color: '#f59e0b', label: 'ESCALATION', prefix: 'Action Needed Soon' },
    'due_today': { color: '#ef4444', label: 'ACTION REQUIRED', prefix: 'Due Today' },
    'overdue': { color: '#dc2626', label: 'OVERDUE', prefix: 'Past Due' }
  };

  const style = urgencyMap[threshold];
  const email_subject = `Compliance ${style.label}: ${ob.obligation_name} due ${ob.due_date}`;
  const email_html = `<!DOCTYPE html><html><body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;"><div style="border-left: 4px solid ${style.color}; padding: 16px; margin: 16px 0;"><h2 style="color: ${style.color}; margin: 0 0 8px;">${style.prefix}: ${ob.obligation_name}</h2><p><strong>Status:</strong> ${style.label}</p><p><strong>Due Date:</strong> ${ob.due_date}</p><p><strong>Days Until Due:</strong> ${daysUntilDue}</p><p><strong>Description:</strong> ${ob.description || 'N/A'}</p><p><strong>Owner:</strong> ${ob.owner || 'N/A'}</p><p><strong>Category:</strong> ${ob.category || 'N/A'}</p>${ob.notes ? '<p><strong>Notes:</strong> ' + ob.notes + '</p>' : ''}</div><p style="color: #666; font-size: 12px;">Compliance Sentinel | Faith & Harmony LLC | Automated Governance System</p></body></html>`;

  results.push({
    json: {
      ...ob,
      days_until_due: daysUntilDue,
      threshold,
      needs_sms: threshold === '14_day' || threshold === 'overdue',
      needs_email: true,
      email_html,
      email_subject,
      current_quarter: quarter,
      fiscal_year: today.getFullYear(),
      sms_message: (threshold === '14_day' || threshold === 'overdue')
        ? `COMPLIANCE ${style.label}: ${ob.obligation_name} due in ${daysUntilDue} days. Action needed. Check email for details.`
        : ''
    }
  });
}

return results.length > 0 ? results : [{ json: { _empty: true, threshold: 'no_action' } }];

// Check for recently completed recurring obligations that need auto-renewal
// Only runs on weekly Monday path
const items = $input.all();
const results = [];
const renewals = [];

const today = new Date();
const sevenDaysAgo = new Date(today);
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

for (const item of items) {
  const ob = item.json;
  // Pass through all items for downstream processing
  results.push(item);

  // Check if this obligation was recently completed and is recurring
  if (ob.status === 'complete' && ob.completed_at) {
    const completedAt = new Date(ob.completed_at);
    const recurrence = ob.recurrence;

    // Skip non-recurring obligations
    if (recurrence === 'one_time' || recurrence === 'as_needed') continue;

    // Only process completions within the last 7 days
    if (completedAt < sevenDaysAgo) continue;

    // Calculate next due date
    let nextDueDate = new Date(completedAt);
    switch (recurrence) {
      case 'monthly':
        nextDueDate.setMonth(nextDueDate.getMonth() + 1);
        break;
      case 'quarterly':
        nextDueDate.setMonth(nextDueDate.getMonth() + 3);
        break;
      case 'annual':
        nextDueDate.setFullYear(nextDueDate.getFullYear() + 1);
        break;
      case 'biennial':
        nextDueDate.setFullYear(nextDueDate.getFullYear() + 2);
        break;
      default:
        continue;
    }

    renewals.push({
      json: {
        obligation_name: ob.obligation_name,
        category: ob.category,
        description: ob.description,
        due_date: nextDueDate.toISOString().split('T')[0],
        recurrence: ob.recurrence,
        status: 'pending',
        owner: ob.owner,
        source_document: ob.source_document,
        notes: `Auto-renewed from completed obligation (completed ${completedAt.toISOString().split('T')[0]})`,
        _is_renewal: true,
        _parent_obligation_name: ob.obligation_name
      }
    });
  }
}

// Output 0: all obligations for threshold routing
// Output 1: renewals to create (may be empty)
// n8n Code node can only return one output, so we tag renewals
return results.concat(renewals);

// SUMMARY_HOOK: Weekly summary pipeline starts here
// Collect all obligation data for the weekly summary
const allObs = $('\[SCAN\] Query All Obligations').all();
const obligations = allObs.map(item => item.json);

return [{ json: { obligations_data: obligations, obligations_count: obligations.length } }];

// Generate minimal PDF for compliance summary
function createCompliancePDF(title, dateStr, summaryText, obligations) {
  const lines = [];
  lines.push(title);
  lines.push('Generated: ' + dateStr);
  lines.push('');

  if (summaryText) {
    const summaryLines = summaryText.split('\n');
    for (const line of summaryLines) {
      lines.push(line);
    }
  } else {
    lines.push('Status Summary:');
    lines.push('');
    const counts = { pending: 0, in_progress: 0, complete: 0, overdue: 0, waived: 0 };
    obligations.forEach(ob => { counts[ob.status] = (counts[ob.status] || 0) + 1; });
    Object.entries(counts).forEach(([status, count]) => {
      if (count > 0) lines.push('  ' + status + ': ' + count);
    });
    lines.push('');
    lines.push('Obligation Details:');
    lines.push('');
    obligations.forEach(ob => {
      lines.push(ob.obligation_name + ' | ' + ob.status + ' | Due: ' + ob.due_date + ' | Owner: ' + ob.owner);
    });
  }

  const pageLines = lines.slice(0, 45);
  const escapedLines = pageLines.map(line =>
    line.replace(/\\/g, '\\\\').replace(/\(/g, '\\(').replace(/\)/g, '\\)')
  );
  const textContent = escapedLines.map((line, i) =>
    'BT /F1 10 Tf 50 ' + (750 - i * 16) + ' Td (' + line + ') Tj ET'
  ).join('\n');

  const streamLength = textContent.length;
  return '%PDF-1.4\n' +
    '1 0 obj << /Type /Catalog /Pages 2 0 R >> endobj\n' +
    '2 0 obj << /Type /Pages /Kids [3 0 R] /Count 1 >> endobj\n' +
    '3 0 obj << /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >> endobj\n' +
    '4 0 obj << /Length ' + streamLength + ' >> stream\n' +
    textContent + '\n' +
    'endstream endobj\n' +
    '5 0 obj << /Type /Font /Subtype /Type1 /BaseFont /Helvetica >> endobj\n' +
    'xref\n0 6\n' +
    '0000000000 65535 f \n' +
    '0000000009 00000 n \n' +
    '0000000058 00000 n \n' +
    '0000000115 00000 n \n' +
    '0000000266 00000 n \n' +
    'trailer << /Size 6 /Root 1 0 R >>\n' +
    'startxref\n' + (350 + streamLength) + '\n' +
    '%%EOF';
}

// Get obligations from upstream
const prevNode = $('\[SUMMARY\] Prepare Summary Data').first().json;
const obligations = prevNode.obligations_data || [];

// Check if AI summary succeeded
let aiSummary = null;
try {
  const aiResponse = $input.first().json;
  if (aiResponse && aiResponse.content && aiResponse.content[0] && aiResponse.content[0].text) {
    aiSummary = aiResponse.content[0].text;
  }
} catch (e) { /* AI failed, use fallback */ }

// Calculate ISO week number
const now = new Date();
const year = now.getFullYear();
const jan1 = new Date(year, 0, 1);
const dayOfYear = Math.ceil((now - jan1) / 86400000);
const weekNum = Math.ceil((dayOfYear + jan1.getDay() + 1) / 7);
const weekStr = 'W' + String(weekNum).padStart(2, '0');
const fileName = year + '-' + weekStr + '_compliance_status.pdf';
const filePath = 'compliance/' + fileName;

const pdfContent = createCompliancePDF(
  'Faith & Harmony LLC - Weekly Compliance Status',
  now.toISOString(),
  aiSummary,
  obligations
);

const pdfBase64 = Buffer.from(pdfContent, 'utf-8').toString('base64');

return [{
  json: {
    file_name: fileName,
    file_path: filePath,
    pdf_base64: pdfBase64,
    obligations_summary: aiSummary || 'AI summary unavailable - raw status table included in PDF',
    obligations_data: obligations,
    week_label: year + '-' + weekStr
  }
}];
